// CREA Eligibility Gate
// Exit immediately if not eligible for CREA review

const item = $input.item.json;

// Extract relevant fields
const mode = item.mode || '';
const confidence = parseFloat(item.confidence) || 0;
const status = item.status || '';
const risk_level = item.risk_level || '';
const human_approval_received = item.human_approval_received || false;

// Check eligibility conditions
const isEligible = (
  mode === 'execute' &&
  confidence >= 0.90 &&
  status !== 'paused' && status !== 'waiting' &&
  !(['medium', 'high'].includes(risk_level) && human_approval_received !== true)
);

if (!isEligible) {
  // Not eligible - return SKIPPED status
  return {
    json: {
      ...item,
      status: 'SKIPPED_NOT_ELIGIBLE',
      eligible: false,
      eligibility_reason: `Failed eligibility check: mode=${mode}, confidence=${confidence}, status=${status}, risk_level=${risk_level}, human_approval=${human_approval_received}`
    }
  };
}

// Eligible - pass through with eligible flag
return {
  json: {
    ...item,
    eligible: true
  }
};

// Final Decision Node - Format CREA Decision in Strict Schema
// Extract aggregated risk analysis results
const aggregatedData = $input.all();

// Initialize decision variables
let approved = true;
let riskLevel = 'low';
let checksRun = [];
let violationReason = '';
let violations = [];
let inputRiskLevel = 'low';
let requestId = 'UNKNOWN';
let systemConfidence = 0;

// Extract request_id and confidence from first item
if (aggregatedData.length > 0) {
  const firstItem = aggregatedData[0].json;
  if (firstItem.request_id) {
    requestId = firstItem.request_id;
  }
  if (firstItem.confidence !== undefined) {
    systemConfidence = firstItem.confidence;
  }
  if (firstItem.risk_level) {
    inputRiskLevel = firstItem.risk_level;
  }
}

// Define which checks run for each risk tier
const riskTierChecks = {
  'low': ['policy_validation'],
  'medium': ['policy_validation', 'legal_compliance'],
  'high': ['policy_validation', 'legal_compliance', 'bias_detection', 'safety_override']
};

const expectedChecks = riskTierChecks[inputRiskLevel] || ['policy_validation'];

// Process each agent's results
for (const item of aggregatedData) {
  const json = item.json;

  // Bias Detection Agent
  if (json.bias_detected !== undefined) {
    if (!checksRun.includes('bias_detection')) {
      checksRun.push('bias_detection');
    }
    if (json.bias_detected) {
      approved = false;
      violations.push(`Bias detected: ${json.explanation}`);
      if (json.bias_severity === 'high') {
        riskLevel = 'high';
      } else if (json.bias_severity === 'medium' && riskLevel !== 'high') {
        riskLevel = 'medium';
      }
    }
  }

  // Legal Compliance Agent
  if (json.legal_violation !== undefined) {
    if (!checksRun.includes('legal_compliance')) {
      checksRun.push('legal_compliance');
    }
    if (json.legal_violation) {
      approved = false;
      violations.push(`Legal violation: ${json.explanation}`);
      if (json.severity === 'high') {
        riskLevel = 'high';
      } else if (json.severity === 'medium' && riskLevel !== 'high') {
        riskLevel = 'medium';
      }
    }
  }

  // Safety Override Agent
  if (json.unsafe !== undefined) {
    if (!checksRun.includes('safety_override')) {
      checksRun.push('safety_override');
    }
    if (json.unsafe) {
      approved = false;
      violations.push(`Safety risk: ${json.explanation}`);
      if (json.safety_risk_level === 'high') {
        riskLevel = 'high';
      } else if (json.safety_risk_level === 'medium' && riskLevel !== 'high') {
        riskLevel = 'medium';
      }
    }
  }

  // Policy Validation Agent
  if (json.policy_violation !== undefined) {
    if (!checksRun.includes('policy_validation')) {
      checksRun.push('policy_validation');
    }
    if (json.policy_violation) {
      approved = false;
      violations.push(`Policy violation: ${json.explanation}`);
      if (json.severity === 'high') {
        riskLevel = 'high';
      } else if (json.severity === 'medium' && riskLevel !== 'high') {
        riskLevel = 'medium';
      }
    }
  }
}

// Format violation reason
if (violations.length > 0) {
  violationReason = violations.join('; ');
} else {
  violationReason = 'No violations detected';
}

// Build final CREA decision in strict schema
const creaDecision = {
  crea_decision: approved ? 'approved' : 'blocked',
  risk_level: riskLevel,
  input_risk_level: inputRiskLevel,
  checks_run: checksRun,
  violation_reason: violationReason,
  authority_source: 'CREA',
  timestamp: new Date().toISOString(),
  request_id: requestId,
  confidence: systemConfidence
};

return [{ json: creaDecision }];

// CREA INPUT VALIDATION GATE (NON-NEGOTIABLE)
// Immediately reject execution if critical inputs are missing

const item = $input.item.json;

// Extract required fields
const request_id = item.request_id;
const confidence = item.confidence;
const risk_level = item.risk_level;
const payload = item.payload;

// Validation: Check for missing required fields
const missingFields = [];

if (request_id === undefined || request_id === null || request_id === '') {
  missingFields.push('request_id');
}

if (confidence === undefined || confidence === null) {
  missingFields.push('confidence');
}

if (risk_level === undefined || risk_level === null || risk_level === '') {
  missingFields.push('risk_level');
}

if (payload === undefined || payload === null || payload === '') {
  missingFields.push('payload');
}

// REJECT if any required field is missing
if (missingFields.length > 0) {
  return {
    json: {
      workflow_id: 'WF-8',
      request_id: request_id || 'UNKNOWN',
      decision: 'TEMPORARY_BLOCK',
      blocked_by: 'CREA',
      reason: `CREA input validation failed: missing required fields [${missingFields.join(', ')}]`,
      confidence: null,
      risk_level: 'high',
      binding: true,
      expires: null,
      audit: {
        timestamp: new Date().toISOString(),
        evaluated_by: 'CREA',
        notes: ['Input validation gate rejected incomplete request']
      },
      status: 'rejected',
      validation_failed: true
    }
  };
}

// Pass through if validation succeeds
return {
  json: {
    ...item,
    validation_passed: true
  }
};

// SYSTEM CONFIDENCE VALIDATION
// Verify confidence is a valid system-level trust metric

const item = $input.item.json;

// Check if validation already failed
if (item.validation_failed === true) {
  return { json: item };
}

const confidence = item.confidence;

// Validate confidence is a number between 0.0 and 1.0
const isValidConfidence = (
  typeof confidence === 'number' &&
  !isNaN(confidence) &&
  confidence >= 0.0 &&
  confidence <= 1.0
);

if (!isValidConfidence) {
  return {
    json: {
      workflow_id: 'WF-8',
      request_id: item.request_id || 'UNKNOWN',
      decision: 'TEMPORARY_BLOCK',
      blocked_by: 'CREA',
      reason: `Invalid system confidence: received ${confidence}, expected number between 0.0 and 1.0`,
      confidence: null,
      risk_level: 'high',
      binding: true,
      expires: null,
      audit: {
        timestamp: new Date().toISOString(),
        evaluated_by: 'CREA',
        notes: ['Confidence validation failed - invalid confidence value']
      },
      status: 'rejected',
      validation_failed: true
    }
  };
}

// Pass through if confidence is valid
return {
  json: {
    ...item,
    confidence_validated: true
  }
};

// BINDING DECISION OUTPUT (MANDATORY)
// Transform CREA decision into strict binding decision object

const item = $input.item.json;

// If validation failed earlier, return that rejection
if (item.validation_failed === true) {
  return { json: item };
}

// Extract CREA decision from Final Decision Node
const creaDecision = item.crea_decision || 'blocked';
const riskLevel = item.risk_level || 'high';
const violationReason = item.violation_reason || 'Unknown violation';
const checksRun = item.checks_run || [];

// Determine final decision
const decision = creaDecision === 'approved' ? 'APPROVED' : 'TEMPORARY_BLOCK';
const blockedBy = decision === 'TEMPORARY_BLOCK' ? 'CREA' : null;

// Extract original request data
const requestId = item.request_id || 'UNKNOWN';
const systemConfidence = item.confidence;

// Build BINDING DECISION OBJECT (strict schema)
const bindingDecision = {
  workflow_id: 'WF-8',
  request_id: requestId,
  decision: decision,
  blocked_by: blockedBy,
  reason: decision === 'TEMPORARY_BLOCK' ? violationReason : 'All CREA checks passed',
  confidence: systemConfidence,
  risk_level: riskLevel,
  binding: true,
  expires: null,
  audit: {
    timestamp: new Date().toISOString(),
    evaluated_by: 'CREA',
    notes: [
      `Checks executed: ${checksRun.join(', ')}`,
      `Decision: ${decision}`,
      `Authority: FINAL AND ABSOLUTE`
    ]
  }
};

return { json: bindingDecision };
